// PROBLEMA 1: Cálculo pesado no body:
struct ListaView: View {
    let itens: [Item]

    var body: some View {
        // ordenar 10000 itens a cada recálculo do body:
        let ordenados = itens.sorted { $0.data > $1.data }  // LENTO
        return List(ordenados) { item in ItemView(item: item) }
    }
}

// SOLUÇÃO: Calcular fora do body:
struct ListaView: View {
    let itensOrdenados: [Item]  // calculado antes, passado como parâmetro

    var body: some View {
        List(itensOrdenados) { item in ItemView(item: item) }
    }
}

// PROBLEMA 2: VStack com muitos itens (não lazy):
ScrollView {
    VStack {  // cria 10000 Views de uma vez
        ForEach(itens) { item in ItemView(item: item) }
    }
}

// SOLUÇÃO: LazyVStack:
ScrollView {
    LazyVStack {
        ForEach(itens) { item in ItemView(item: item) }
    }
}

